import React, { useState, useEffect } from 'react';
import {
  Settings as SettingsIcon,
  Server,
  Users,
  Palette,
  Brain,
  Key,
  Save,
  RefreshCw,
  Plus,
  Edit,
  Trash2,
  X,
  Check,
  AlertCircle,
  Eye,
  EyeOff,
  Shield,
  Database,
  Globe,
  Cpu,
  MessageSquare
} from 'lucide-react';

function Settings() {
  const [activeTab, setActiveTab] = useState('users');
  const [loading, setLoading] = useState(false);
  const [notification, setNotification] = useState(null);

  // Users State
  const [users, setUsers] = useState([
    { id: 1, username: 'admin', email: 'admin@lorcgr.local', role: 'admin', created_at: '2026-02-01', last_login: '2026-02-14', active: true },
    { id: 2, username: 'noc', email: 'noc@lorcgr.local', role: 'operator', created_at: '2026-02-10', last_login: '2026-02-13', active: true },
  ]);
  const [userDialogOpen, setUserDialogOpen] = useState(false);
  const [selectedUser, setSelectedUser] = useState(null);
  const [userForm, setUserForm] = useState({ username: '', email: '', password: '', role: 'operator' });

  // API Settings State
  const [apiSettings, setApiSettings] = useState({
    librenms_url: 'http://localhost/librenms/api/v0',
    librenms_token: '',
    phpipam_url: 'http://localhost/phpipam/api',
    phpipam_app_id: '',
    phpipam_app_key: '',
  });

  // Theme State
  const [themeSettings, setThemeSettings] = useState({
    current_theme: 'dark',
    primary_color: '#6366f1',
    sidebar_collapsed: false,
    show_pppoe_count: true,
    auto_refresh_interval: 60,
  });

  // AI Settings State
  const [aiSettings, setAiSettings] = useState({
    enabled: true,
    provider: 'openai',
    api_key: '',
    api_endpoint: '',
    model: 'gpt-4',
    max_tokens: 2000,
    temperature: 0.7,
    memory_enabled: true,
    auto_analyze: true,
    analyze_interval: 300,
  });

  // AI Knowledge Base
  const [knowledgeEntries, setKnowledgeEntries] = useState([
    { id: 1, type: 'problem', title: 'Interface DOWN no BRAS', solution: 'Verificar cabo físico e status docliente PPPoE', device: 'BRAS_NE8000', created_at: '2026-02-10' },
    { id: 2, type: 'solution', title: 'PPPoE desconectando', solution: 'Ajustar MTU para 1492 no profile PPPoE', device: 'PPPoE_CARDOSO_MOREIRA', created_at: '2026-02-12' },
  ]);
  const [knowledgeDialogOpen, setKnowledgeDialogOpen] = useState(false);
  const [knowledgeForm, setKnowledgeForm] = useState({ type: 'problem', title: '', solution: '', device: '' });

  const roles = [
    { value: 'admin', label: 'Administrador', desc: 'Acesso total ao sistema' },
    { value: 'operator', label: 'Operador NOC', desc: 'Operações e visualização' },
    { value: 'viewer', label: 'Visualizador', desc: 'Apenas visualização' },
  ];

  const aiProviders = [
    { value: 'openai', label: 'OpenAI (GPT-4)' },
    { value: 'anthropic', label: 'Anthropic (Claude)' },
    { value: 'google', label: 'Google (Gemini)' },
    { value: 'local', label: 'Modelo Local (Ollama)' },
    { value: 'custom', label: 'API Customizada' },
  ];

  const themes = [
    { value: 'dark', label: 'Dark Mode (NOC)', colors: { bg: '#0f0f1a', primary: '#6366f1' } },
    { value: 'midnight', label: 'Midnight Blue', colors: { bg: '#0a0a1a', primary: '#3b82f6' } },
    { value: 'forest', label: 'Forest', colors: { bg: '#0a1a0f', primary: '#22c55e' } },
    { value: 'sunset', label: 'Sunset', colors: { bg: '#1a0f0f', primary: '#f97316' } },
  ];

  const showNotification = (message, type = 'success') => {
    setNotification({ message, type });
    setTimeout(() => setNotification(null), 3000);
  };

  // User handlers
  const handleOpenUserDialog = (user = null) => {
    if (user) {
      setSelectedUser(user);
      setUserForm({ username: user.username, email: user.email, password: '', role: user.role });
    } else {
      setSelectedUser(null);
      setUserForm({ username: '', email: '', password: '', role: 'operator' });
    }
    setUserDialogOpen(true);
  };

  const handleSaveUser = async () => {
    setLoading(true);
    // TODO: Call API to create user in LOR CGR, LibreNMS, phpIPAM
    setTimeout(() => {
      if (selectedUser) {
        setUsers(prev => prev.map(u => u.id === selectedUser.id ? { ...u, ...userForm } : u));
        showNotification('Usuário atualizado em todos os sistemas!');
      } else {
        setUsers(prev => [...prev, { ...userForm, id: Date.now(), created_at: new Date().toISOString().slice(0, 10), last_login: '-', active: true }]);
        showNotification('Usuário criado no LOR CGR, LibreNMS e phpIPAM!');
      }
      setUserDialogOpen(false);
      setLoading(false);
    }, 1000);
  };

  const handleDeleteUser = (userId) => {
    if (confirm('Remover usuário de TODOS os sistemas (LOR CGR, LibreNMS, phpIPAM)?')) {
      setUsers(prev => prev.filter(u => u.id !== userId));
      showNotification('Usuário removido de todos os sistemas');
    }
  };

  // Settings handlers
  const handleSaveApiSettings = () => {
    setLoading(true);
    setTimeout(() => {
      showNotification('Configurações de API salvas!');
      setLoading(false);
    }, 500);
  };

  const handleSaveThemeSettings = () => {
    setLoading(true);
    setTimeout(() => {
      showNotification('Tema salvo!');
      setLoading(false);
    }, 500);
  };

  const handleSaveAiSettings = () => {
    setLoading(true);
    setTimeout(() => {
      showNotification('Configurações de IA salvas!');
      setLoading(false);
    }, 500);
  };

  // Knowledge handlers
  const handleOpenKnowledgeDialog = () => {
    setKnowledgeForm({ type: 'problem', title: '', solution: '', device: '' });
    setKnowledgeDialogOpen(true);
  };

  const handleSaveKnowledge = () => {
    setKnowledgeEntries(prev => [...prev, { ...knowledgeForm, id: Date.now(), created_at: new Date().toISOString().slice(0, 10) }]);
    setKnowledgeDialogOpen(false);
    showNotification('Conhecimento adicionado à base da IA!');
  };

  const tabs = [
    { id: 'users', label: 'Usuários', icon: Users },
    { id: 'apis', label: 'Integrações', icon: Server },
    { id: 'theme', label: 'Aparência', icon: Palette },
    { id: 'ai', label: 'Inteligência Artificial', icon: Brain },
  ];

  return (
    <div className="space-y-6">
      {/* Notification */}
      {notification && (
        <div className={'fixed top-4 right-4 z-50 px-4 py-3 rounded-lg shadow-lg ' + (notification.type === 'error' ? 'bg-red-500' : 'bg-green-500') + ' text-white'}>
          {notification.message}
        </div>
      )}

      {/* Header */}
      <div>
        <h1 className="text-3xl font-bold tracking-tight">Configurações</h1>
        <p className="text-muted-foreground">Gerenciamento do sistema LOR CGR</p>
      </div>

      {/* Tabs */}
      <div className="flex border-b border-border overflow-x-auto">
        {tabs.map((tab) => {
          const Icon = tab.icon;
          return (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={'flex items-center gap-2 px-4 py-3 text-sm font-medium whitespace-nowrap ' + (activeTab === tab.id ? 'border-b-2 border-primary text-primary' : 'text-muted-foreground hover:text-foreground')}
            >
              <Icon className="h-4 w-4" />
              {tab.label}
            </button>
          );
        })}
      </div>

      {/* Users Tab */}
      {activeTab === 'users' && (
        <div className="space-y-6">
          <div className="flex justify-between items-center">
            <div>
              <h2 className="text-xl font-semibold">Gerenciamento de Usuários</h2>
              <p className="text-sm text-muted-foreground">Usuários são sincronizados com LibreNMS e phpIPAM</p>
            </div>
            <button onClick={() => handleOpenUserDialog()} className="px-4 py-2 bg-primary text-white rounded-lg hover:bg-primary/90 flex items-center gap-2">
              <Plus className="h-4 w-4" /> Novo Usuário
            </button>
          </div>

          <div className="bg-card rounded-lg border border-border overflow-hidden">
            <table className="w-full">
              <thead className="bg-secondary/30">
                <tr>
                  <th className="text-left p-4 text-sm font-medium text-muted-foreground">Usuário</th>
                  <th className="text-left p-4 text-sm font-medium text-muted-foreground">Email</th>
                  <th className="text-left p-4 text-sm font-medium text-muted-foreground">Perfil</th>
                  <th className="text-left p-4 text-sm font-medium text-muted-foreground">Último Acesso</th>
                  <th className="text-left p-4 text-sm font-medium text-muted-foreground">Status</th>
                  <th className="text-right p-4 text-sm font-medium text-muted-foreground">Ações</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {users.map((user) => (
                  <tr key={user.id} className="hover:bg-secondary/30">
                    <td className="p-4">
                      <div className="font-medium">{user.username}</div>
                      <div className="text-xs text-muted-foreground">Criado em {user.created_at}</div>
                    </td>
                    <td className="p-4 text-sm">{user.email}</td>
                    <td className="p-4">
                      <span className={'px-2 py-1 rounded text-xs ' + (user.role === 'admin' ? 'bg-purple-500/20 text-purple-400' : user.role === 'operator' ? 'bg-blue-500/20 text-blue-400' : 'bg-gray-500/20 text-gray-400')}>
                        {roles.find(r => r.value === user.role)?.label}
                      </span>
                    </td>
                    <td className="p-4 text-sm text-muted-foreground">{user.last_login}</td>
                    <td className="p-4">
                      <span className={'px-2 py-1 rounded text-xs ' + (user.active ? 'bg-green-500/20 text-green-400' : 'bg-red-500/20 text-red-400')}>
                        {user.active ? 'Ativo' : 'Inativo'}
                      </span>
                    </td>
                    <td className="p-4 text-right">
                      <button onClick={() => handleOpenUserDialog(user)} className="p-2 hover:bg-secondary rounded">
                        <Edit className="h-4 w-4" />
                      </button>
                      <button onClick={() => handleDeleteUser(user.id)} className="p-2 hover:bg-secondary text-red-500 rounded">
                        <Trash2 className="h-4 w-4" />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          {/* Permissions Info */}
          <div className="bg-card rounded-lg border border-border p-4">
            <h3 className="font-semibold mb-3 flex items-center gap-2"><Shield className="h-4 w-4" /> Níveis de Permissão</h3>
            <div className="grid gap-3 md:grid-cols-3">
              {roles.map((role) => (
                <div key={role.value} className="p-3 bg-secondary/50 rounded-lg">
                  <div className="font-medium text-sm">{role.label}</div>
                  <div className="text-xs text-muted-foreground mt-1">{role.desc}</div>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* APIs Tab */}
      {activeTab === 'apis' && (
        <div className="space-y-6">
          <div>
            <h2 className="text-xl font-semibold">Integrações com Sistemas Externos</h2>
            <p className="text-sm text-muted-foreground">Configure as conexões com LibreNMS, phpIPAM e outros sistemas</p>
          </div>

          {/* LibreNMS */}
          <div className="bg-card rounded-lg border border-border p-6">
            <div className="flex items-center gap-3 mb-4">
              <div className="p-2 bg-blue-500/20 rounded-lg"><Database className="h-5 w-5 text-blue-400" /></div>
              <div>
                <h3 className="font-semibold">LibreNMS</h3>
                <p className="text-xs text-muted-foreground">Sistema de monitoramento de rede</p>
              </div>
            </div>
            <div className="grid gap-4 md:grid-cols-2">
              <div>
                <label className="block text-sm font-medium mb-1">URL da API</label>
                <input type="text" value={apiSettings.librenms_url} onChange={(e) => setApiSettings({ ...apiSettings, librenms_url: e.target.value })} className="w-full px-3 py-2 bg-secondary border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary" placeholder="http://localhost/librenms/api/v0" />
              </div>
              <div>
                <label className="block text-sm font-medium mb-1">API Token</label>
                <input type="password" value={apiSettings.librenms_token} onChange={(e) => setApiSettings({ ...apiSettings, librenms_token: e.target.value })} className="w-full px-3 py-2 bg-secondary border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary" placeholder="••••••••" />
              </div>
            </div>
            <button className="mt-4 px-4 py-2 border border-border rounded-lg hover:bg-secondary text-sm">Testar Conexão</button>
          </div>

          {/* phpIPAM */}
          <div className="bg-card rounded-lg border border-border p-6">
            <div className="flex items-center gap-3 mb-4">
              <div className="p-2 bg-green-500/20 rounded-lg"><Globe className="h-5 w-5 text-green-400" /></div>
              <div>
                <h3 className="font-semibold">phpIPAM</h3>
                <p className="text-xs text-muted-foreground">Gerenciamento de endereços IP</p>
              </div>
            </div>
            <div className="grid gap-4 md:grid-cols-3">
              <div>
                <label className="block text-sm font-medium mb-1">URL da API</label>
                <input type="text" value={apiSettings.phpipam_url} onChange={(e) => setApiSettings({ ...apiSettings, phpipam_url: e.target.value })} className="w-full px-3 py-2 bg-secondary border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary" />
              </div>
              <div>
                <label className="block text-sm font-medium mb-1">App ID</label>
                <input type="text" value={apiSettings.phpipam_app_id} onChange={(e) => setApiSettings({ ...apiSettings, phpipam_app_id: e.target.value })} className="w-full px-3 py-2 bg-secondary border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary" />
              </div>
              <div>
                <label className="block text-sm font-medium mb-1">App Key</label>
                <input type="password" value={apiSettings.phpipam_app_key} onChange={(e) => setApiSettings({ ...apiSettings, phpipam_app_key: e.target.value })} className="w-full px-3 py-2 bg-secondary border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary" />
              </div>
            </div>
            <button className="mt-4 px-4 py-2 border border-border rounded-lg hover:bg-secondary text-sm">Testar Conexão</button>
          </div>

          <button onClick={handleSaveApiSettings} disabled={loading} className="px-4 py-2 bg-primary text-white rounded-lg hover:bg-primary/90 flex items-center gap-2">
            {loading ? <RefreshCw className="h-4 w-4 animate-spin" /> : <Save className="h-4 w-4" />}
            Salvar Configurações de API
          </button>
        </div>
      )}

      {/* Theme Tab */}
      {activeTab === 'theme' && (
        <div className="space-y-6">
          <div>
            <h2 className="text-xl font-semibold">Aparência e Temas</h2>
            <p className="text-sm text-muted-foreground">Personalize a interface do sistema</p>
          </div>

          {/* Theme Selection */}
          <div className="bg-card rounded-lg border border-border p-6">
            <h3 className="font-semibold mb-4">Selecione um Tema</h3>
            <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
              {themes.map((theme) => (
                <div
                  key={theme.value}
                  onClick={() => setThemeSettings({ ...themeSettings, current_theme: theme.value })}
                  className={'p-4 rounded-lg border-2 cursor-pointer transition-all ' + (themeSettings.current_theme === theme.value ? 'border-primary' : 'border-border hover:border-primary/50')}
                  style={{ backgroundColor: theme.colors.bg }}
                >
                  <div className="flex items-center justify-between mb-2">
                    <span className="text-sm font-medium">{theme.label}</span>
                    {themeSettings.current_theme === theme.value && <Check className="h-4 w-4 text-primary" />}
                  </div>
                  <div className="h-8 rounded" style={{ backgroundColor: theme.colors.primary }} />
                </div>
              ))}
            </div>
          </div>

          {/* Display Options */}
          <div className="bg-card rounded-lg border border-border p-6">
            <h3 className="font-semibold mb-4">Opções de Exibição</h3>
            <div className="space-y-4">
              <div className="flex items-center justify-between p-3 bg-secondary/50 rounded-lg">
                <div>
                  <div className="font-medium text-sm">Mostrar contador PPPoE</div>
                  <div className="text-xs text-muted-foreground">Exibir contagem de sessões PPPoE no dashboard</div>
                </div>
                <button onClick={() => setThemeSettings({ ...themeSettings, show_pppoe_count: !themeSettings.show_pppoe_count })} className={'w-12 h-6 rounded-full transition-colors ' + (themeSettings.show_pppoe_count ? 'bg-primary' : 'bg-secondary border border-border')}>
                  <div className={'w-5 h-5 rounded-full bg-white transition-transform ' + (themeSettings.show_pppoe_count ? 'translate-x-6' : 'translate-x-0.5')} />
                </button>
              </div>
              <div className="p-3 bg-secondary/50 rounded-lg">
                <div className="flex items-center justify-between mb-2">
                  <div className="font-medium text-sm">Intervalo de atualização automática</div>
                  <span className="text-sm text-muted-foreground">{themeSettings.auto_refresh_interval}s</span>
                </div>
                <input type="range" min="10" max="300" value={themeSettings.auto_refresh_interval} onChange={(e) => setThemeSettings({ ...themeSettings, auto_refresh_interval: parseInt(e.target.value) })} className="w-full" />
              </div>
            </div>
          </div>

          <button onClick={handleSaveThemeSettings} disabled={loading} className="px-4 py-2 bg-primary text-white rounded-lg hover:bg-primary/90 flex items-center gap-2">
            {loading ? <RefreshCw className="h-4 w-4 animate-spin" /> : <Save className="h-4 w-4" />}
            Salvar Tema
          </button>
        </div>
      )}

      {/* AI Tab */}
      {activeTab === 'ai' && (
        <div className="space-y-6">
          <div>
            <h2 className="text-xl font-semibold">Inteligência Artificial</h2>
            <p className="text-sm text-muted-foreground">Configure a IA para análise automatizada e assistência</p>
          </div>

          {/* AI Provider */}
          <div className="bg-card rounded-lg border border-border p-6">
            <div className="flex items-center justify-between mb-4">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-purple-500/20 rounded-lg"><Brain className="h-5 w-5 text-purple-400" /></div>
                <div>
                  <h3 className="font-semibold">Provedor de IA</h3>
                  <p className="text-xs text-muted-foreground">Selecione qual IA será utilizada</p>
                </div>
              </div>
              <button onClick={() => setAiSettings({ ...aiSettings, enabled: !aiSettings.enabled })} className={'w-12 h-6 rounded-full transition-colors ' + (aiSettings.enabled ? 'bg-primary' : 'bg-secondary border border-border')}>
                <div className={'w-5 h-5 rounded-full bg-white transition-transform ' + (aiSettings.enabled ? 'translate-x-6' : 'translate-x-0.5')} />
              </button>
            </div>

            {aiSettings.enabled && (
              <>
                <div className="grid gap-4 md:grid-cols-2 mb-4">
                  <div>
                    <label className="block text-sm font-medium mb-1">Provedor</label>
                    <select value={aiSettings.provider} onChange={(e) => setAiSettings({ ...aiSettings, provider: e.target.value })} className="w-full px-3 py-2 bg-secondary border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary">
                      {aiProviders.map((p) => <option key={p.value} value={p.value}>{p.label}</option>)}
                    </select>
                  </div>
                  <div>
                    <label className="block text-sm font-medium mb-1">Modelo</label>
                    <input type="text" value={aiSettings.model} onChange={(e) => setAiSettings({ ...aiSettings, model: e.target.value })} className="w-full px-3 py-2 bg-secondary border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary" />
                  </div>
                </div>

                <div className="grid gap-4 md:grid-cols-2 mb-4">
                  <div>
                    <label className="block text-sm font-medium mb-1">API Key</label>
                    <input type="password" value={aiSettings.api_key} onChange={(e) => setAiSettings({ ...aiSettings, api_key: e.target.value })} className="w-full px-3 py-2 bg-secondary border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary" placeholder="sk-..." />
                  </div>
                  <div>
                    <label className="block text-sm font-medium mb-1">API Endpoint (opcional)</label>
                    <input type="text" value={aiSettings.api_endpoint} onChange={(e) => setAiSettings({ ...aiSettings, api_endpoint: e.target.value })} className="w-full px-3 py-2 bg-secondary border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary" placeholder="https://api.openai.com/v1" />
                  </div>
                </div>

                <div className="grid gap-4 md:grid-cols-2">
                  <div>
                    <label className="block text-sm font-medium mb-1">Max Tokens</label>
                    <input type="number" value={aiSettings.max_tokens} onChange={(e) => setAiSettings({ ...aiSettings, max_tokens: parseInt(e.target.value) })} className="w-full px-3 py-2 bg-secondary border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary" />
                  </div>
                  <div>
                    <label className="block text-sm font-medium mb-1">Temperature</label>
                    <input type="number" step="0.1" min="0" max="2" value={aiSettings.temperature} onChange={(e) => setAiSettings({ ...aiSettings, temperature: parseFloat(e.target.value) })} className="w-full px-3 py-2 bg-secondary border border-border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary" />
                  </div>
                </div>
              </>
            )}
          </div>

          {/* AI Auto-Analysis */}
          <div className="bg-card rounded-lg border border-border p-6">
            <h3 className="font-semibold mb-4 flex items-center gap-2"><Cpu className="h-4 w-4" /> Análise Automática</h3>
            <div className="space-y-4">
              <div className="flex items-center justify-between p-3 bg-secondary/50 rounded-lg">
                <div>
                  <div className="font-medium text-sm">Análise Automática</div>
                  <div className="text-xs text-muted-foreground">IA analisa a rede automaticamente</div>
                </div>
                <button onClick={() => setAiSettings({ ...aiSettings, auto_analyze: !aiSettings.auto_analyze })} className={'w-12 h-6 rounded-full transition-colors ' + (aiSettings.auto_analyze ? 'bg-primary' : 'bg-secondary border border-border')}>
                  <div className={'w-5 h-5 rounded-full bg-white transition-transform ' + (aiSettings.auto_analyze ? 'translate-x-6' : 'translate-x-0.5')} />
                </button>
              </div>
              <div className="flex items-center justify-between p-3 bg-secondary/50 rounded-lg">
                <div>
                  <div className="font-medium text-sm">Memória da IA</div>
                  <div className="text-xs text-muted-foreground">Armazena problemas e soluções para aprendizado</div>
                </div>
                <button onClick={() => setAiSettings({ ...aiSettings, memory_enabled: !aiSettings.memory_enabled })} className={'w-12 h-6 rounded-full transition-colors ' + (aiSettings.memory_enabled ? 'bg-primary' : 'bg-secondary border border-border')}>
                  <div className={'w-5 h-5 rounded-full bg-white transition-transform ' + (aiSettings.memory_enabled ? 'translate-x-6' : 'translate-x-0.5')} />
                </button>
              </div>
            </div>
          </div>

          {/* Knowledge Base */}
          <div className="bg-card rounded-lg border border-border p-6">
            <div className="flex items-center justify-between mb-4">
              <h3 className="font-semibold flex items-center gap-2"><MessageSquare className="h-4 w-4" /> Base de Conhecimento da IA</h3>
              <button onClick={handleOpenKnowledgeDialog} className="px-3 py-1.5 bg-primary text-white rounded-lg text-sm flex items-center gap-1">
                <Plus className="h-3 w-3" /> Adicionar
              </button>
            </div>
            <div className="space-y-2">
              {knowledgeEntries.map((entry) => (
                <div key={entry.id} className="p-3 bg-secondary/50 rounded-lg">
                  <div className="flex items-start justify-between">
                    <div>
                      <div className="flex items-center gap-2">
                        <span className={'px-2 py-0.5 rounded text-xs ' + (entry.type === 'problem' ? 'bg-red-500/20 text-red-400' : 'bg-green-500/20 text-green-400')}>
                          {entry.type === 'problem' ? 'Problema' : 'Solução'}
                        </span>
                        <span className="font-medium text-sm">{entry.title}</span>
                      </div>
                      <p className="text-xs text-muted-foreground mt-1">{entry.solution}</p>
                    </div>
                    <button className="p-1 hover:bg-secondary rounded text-red-500">
                      <Trash2 className="h-3 w-3" />
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>

          <button onClick={handleSaveAiSettings} disabled={loading} className="px-4 py-2 bg-primary text-white rounded-lg hover:bg-primary/90 flex items-center gap-2">
            {loading ? <RefreshCw className="h-4 w-4 animate-spin" /> : <Save className="h-4 w-4" />}
            Salvar Configurações de IA
          </button>
        </div>
      )}

      {/* User Dialog */}
      {userDialogOpen && (
        <div className="fixed inset-0 z-[9998] flex items-center justify-center bg-black/50">
          <div className="bg-card rounded-lg border border-border w-full max-w-md p-6">
            <div className="flex items-center justify-between mb-4">
              <h2 className="text-xl font-semibold">{selectedUser ? 'Editar Usuário' : 'Novo Usuário'}</h2>
              <button onClick={() => setUserDialogOpen(false)} className="p-1 hover:bg-secondary rounded">
                <X className="h-5 w-5" />
              </button>
            </div>
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium mb-1">Nome de Usuário</label>
                <input type="text" value={userForm.username} onChange={(e) => setUserForm({ ...userForm, username: e.target.value })} className="w-full px-3 py-2 bg-secondary border border-border rounded-lg" />
              </div>
              <div>
                <label className="block text-sm font-medium mb-1">Email</label>
                <input type="email" value={userForm.email} onChange={(e) => setUserForm({ ...userForm, email: e.target.value })} className="w-full px-3 py-2 bg-secondary border border-border rounded-lg" />
              </div>
              <div>
                <label className="block text-sm font-medium mb-1">Senha</label>
                <input type="password" value={userForm.password} onChange={(e) => setUserForm({ ...userForm, password: e.target.value })} className="w-full px-3 py-2 bg-secondary border border-border rounded-lg" placeholder={selectedUser ? 'Deixe vazio para manter' : ''} />
              </div>
              <div>
                <label className="block text-sm font-medium mb-1">Perfil</label>
                <select value={userForm.role} onChange={(e) => setUserForm({ ...userForm, role: e.target.value })} className="w-full px-3 py-2 bg-secondary border border-border rounded-lg">
                  {roles.map((r) => <option key={r.value} value={r.value}>{r.label}</option>)}
                </select>
              </div>
              <div className="p-3 bg-blue-500/10 border border-blue-500/20 rounded-lg text-sm text-blue-200">
                <strong>Sincronização:</strong> O usuário será criado automaticamente no LibreNMS e phpIPAM.
              </div>
            </div>
            <div className="flex justify-end gap-2 mt-6">
              <button onClick={() => setUserDialogOpen(false)} className="px-4 py-2 border border-border rounded-lg hover:bg-secondary">Cancelar</button>
              <button onClick={handleSaveUser} disabled={loading} className="px-4 py-2 bg-primary text-white rounded-lg flex items-center gap-2">
                {loading ? <RefreshCw className="h-4 w-4 animate-spin" /> : <Save className="h-4 w-4" />}
                Salvar
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Knowledge Dialog */}
      {knowledgeDialogOpen && (
        <div className="fixed inset-0 z-[9998] flex items-center justify-center bg-black/50">
          <div className="bg-card rounded-lg border border-border w-full max-w-md p-6">
            <div className="flex items-center justify-between mb-4">
              <h2 className="text-xl font-semibold">Adicionar Conhecimento</h2>
              <button onClick={() => setKnowledgeDialogOpen(false)} className="p-1 hover:bg-secondary rounded">
                <X className="h-5 w-5" />
              </button>
            </div>
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium mb-1">Tipo</label>
                <select value={knowledgeForm.type} onChange={(e) => setKnowledgeForm({ ...knowledgeForm, type: e.target.value })} className="w-full px-3 py-2 bg-secondary border border-border rounded-lg">
                  <option value="problem">Problema</option>
                  <option value="solution">Solução</option>
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium mb-1">Título</label>
                <input type="text" value={knowledgeForm.title} onChange={(e) => setKnowledgeForm({ ...knowledgeForm, title: e.target.value })} className="w-full px-3 py-2 bg-secondary border border-border rounded-lg" placeholder="Ex: Interface DOWN" />
              </div>
              <div>
                <label className="block text-sm font-medium mb-1">Descrição/Solução</label>
                <textarea value={knowledgeForm.solution} onChange={(e) => setKnowledgeForm({ ...knowledgeForm, solution: e.target.value })} className="w-full px-3 py-2 bg-secondary border border-border rounded-lg h-24 resize-none" placeholder="Descreva o problema e como foi resolvido..." />
              </div>
            </div>
            <div className="flex justify-end gap-2 mt-6">
              <button onClick={() => setKnowledgeDialogOpen(false)} className="px-4 py-2 border border-border rounded-lg hover:bg-secondary">Cancelar</button>
              <button onClick={handleSaveKnowledge} className="px-4 py-2 bg-primary text-white rounded-lg">Salvar</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default Settings;
